int fourSumCount(int* A,int na,int* B,int nb,int* C,int nc,int* D,int nd){
    /* hash map — use C++ for large n */
    int ans=0;
    for(int i=0;i<na;i++) for(int j=0;j<nb;j++)
        for(int k=0;k<nc;k++) for(int l=0;l<nd;l++)
            if(A[i]+B[j]+C[k]+D[l]==0) ans++;
    return ans;
}
